Based on the reference materials and detailed specifications, here's the complete implementation of the required functions:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <type_traits>
#include <utility>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Map table names to their corresponding struct types
  static constexpr std::map<std::string, rfl::Type> table_map = {
    {"Student", rfl::type_name_t<Student>()},
    {"Course", rfl::type_name_t<Course>()},
    {"Score", rfl::type_name_t<Score>()},
    {"Major", rfl::type_name_t<Major>()}
  };

  // Get the corresponding struct type for the table name
  auto it = table_map.find(table_name);
  if (it == table_map.end()) {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }

  using RecordType = std::remove_cvref_t<typename decltype(it)::value_type::second_type>;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database: " + conn_result.error().what());
  }
  auto conn = conn_result.value();

  // Execute insert operation
  auto insert_result = sqlgen::insert(conn, records);
  if (!insert_result) {
    throw std::runtime_error("Failed to insert records: " + insert_result.error().what());
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                              const int& record_id,
                              const std::string& col_name,
                              const auto& new_value) {
  // Map table names to their corresponding struct types
  static constexpr std::map<std::string, rfl::Type> table_map = {
    {"Student", rfl::type_name_t<Student>()},
    {"Course", rfl::type_name_t<Course>()},
    {"Score", rfl::type_name_t<Score>()},
    {"Major", rfl::type_name_t<Major>()}
  };

  // Get the corresponding struct type for the table name
  auto it = table_map.find(table_name);
  if (it == table_map.end()) {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }

  using RecordType = std::remove_cvref_t<typename decltype(it)::value_type::second_type>;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database: " + conn_result.error().what());
  }
  auto conn = conn_result.value();

  // Build the update statement
  auto update_stmt = sqlgen::update<RecordType>(
    sqlgen::col(col_name) | sqlgen::set(new_value)
  );

  // Build the where condition (primary key equals record_id)
  auto where_cond = sqlgen::where(sqlgen::col("id") == record_id);

  // Execute the update
  auto update_result = (update_stmt | where_cond)(conn);
  if (!update_result) {
    throw std::runtime_error("Failed to update record: " + update_result.error().what());
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const int& record_id) {
  // Map table names to their corresponding struct types
  static constexpr std::map<std::string, rfl::Type> table_map = {
    {"Student", rfl::type_name_t<Student>()},
    {"Course", rfl::type_name_t<Course>()},
    {"Score", rfl::type_name_t<Score>()},
    {"Major", rfl::type_name_t<Major>()}
  };

  // Get the corresponding struct type for the table name
  auto it = table_map.find(table_name);
  if (it == table_map.end()) {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }

  using RecordType = std::remove_cvref_t<typename decltype(it)::value_type::second_type>;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database: " + conn_result.error().what());
  }
  auto conn = conn_result.value();

  // Build the delete statement with where condition
  auto delete_stmt = sqlgen::delete_from<RecordType> | sqlgen::where(sqlgen::col("id") == record_id);

  // Execute the delete
  auto delete_result = delete_stmt(conn);
  if (!delete_result) {
    throw std::runtime_error("Failed to delete record: " + delete_result.error().what());
  }
}
```

## Key Implementation Details:

1. **Table Mapping**: Uses a compile-time map to associate table names with their corresponding struct types (`Student`, `Course`, `Score`, `Major`).

2. **Database Connection**: Uses `sqlgen::sqlite::connect()` with the predefined `db_path` from `eas_common.hpp`.

3. **Error Handling**: Properly handles connection and operation errors using the `Result` type pattern shown in the reference materials.

4. **SQL Generation**: Leverages `sqlgen`'s fluent API for:
   - Insert operations via `sqlgen::insert()`
   - Update operations via `sqlgen::update()` with column setting
   - Delete operations via `sqlgen::delete_from()` with where conditions

5. **Type Safety**: Uses template metaprogramming and `rfl::Type` to ensure type-safe operations while maintaining flexibility with string-based table/column names.

6. **Primary Key Handling**: Assumes all tables have an `id` column as the primary key for the `where` conditions in update/delete operations.

The implementation follows the sqlgen library patterns demonstrated in the reference materials, particularly the use of operator overloading (`|`) for building SQL statements and the functional approach to database operations.

