    // Build the query using sqlgen's fluent interface
    auto query = sqlgen::select_from<A>("id"_t1, "name"_t1, "a_id"_t2, "score"_t2)
        | sqlgen::join<B>(sqlgen::col<"id", "t1"> == sqlgen::col<"a_id", "t2">)
        | sqlgen::where(sqlgen::col<"score", "t2"> > 10 && 
                       sqlgen::col<"name", "t1">.like("%x%"))
        | sqlgen::order_by(sqlgen::col<"score", "t2">.desc())
        | sqlgen::limit(10);

    // Convert the query object to SQL string using sqlite::to_sql
    return sqlgen::sqlite::to_sql(query);
