    sqlgen::insert(users)(conn);
    sqlgen::insert(friendships)(conn);

    // 1. Mutual friends using SELF-JOIN
    auto mutual_friends_query = select_from<User, "u1">("username"_t1 | as<"user1_name">, "username"_t2 | as<"user2_name">)
        | inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t2)
        | inner_join<Friendship, "f2">("user_id2"_t1 == "user_id1"_t2)
        | inner_join<User, "u2">("user_id2"_t2 == "user_id"_t3)
        | where("u1"_t1 < "u2"_t3)
        | group_by("u1"_t1, "u2"_t3)
        | having(count() > 0)
        | to<std::vector<FriendConnection>>;

    auto mutual_friends = mutual_friends_query(conn);

    // 2. Users with more than average friends using nested query
    auto avg_friends_query = select_from<User, "u">("user_id"_t1, "username"_t1)
        | left_join<Friendship, "f">("user_id"_t1 == "user_id1"_t2)
        | group_by("user_id"_t1, "username"_t1)
        | to<std::vector<NetworkStats>>;

    auto network_stats = avg_friends_query(conn);

    // Calculate average friend count
    double avg_count = 0;
    if (!network_stats.empty()) {
        int total = 0;
        for (const auto& stat : network_stats) {
            total += stat.friend_count;
        }
        avg_count = static_cast<double>(total) / network_stats.size();
    }

    // Filter users above average
    std::vector<NetworkStats> above_avg;
    std::copy_if(network_stats.begin(), network_stats.end(),
                   std::back_inserter(above_avg),
                   [avg_count](const NetworkStats& s) { return s.friend_count > avg_count; });

    // 3. Friend-of-friend relationships
    auto friend_of_friend_query = select_from<User, "u1">("username"_t1 | as<"user1_name">, "username"_t2 | as<"user2_name">)
        | inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t2)
        | inner_join<Friendship, "f2">("user_id2"_t1 == "user_id1"_t2)
        | inner_join<User, "u2">("user_id2"_t2 == "user_id"_t3)
        | where("u1"_t1 != "u2"_t3 && !exists(select_from<Friendship>("1")
            | where("user_id1"_t1 == "u1"_t1 && "user_id2"_t1 == "u2"_t3))))
        | to<std::vector<Recommendation>>;

    auto friend_of_friend = friend_of_friend_query(conn);

    // 4. Most connected users
    std::sort(above_avg.begin(), above_avg.end(),
                  [](const NetworkStats& a, const NetworkStats& b) {
                      return a.friend_count > b.friend_count;
                  });

    // 5. Same city recommendations
    auto same_city_recs = select_from<User, "u1">("username"_t1 | as<"user1_name">, "username"_t2 | as<"user2_name">)
        | inner_join<User, "u2">("city"_t1 == "city"_t2 && "user_id"_t1 < "user_id"_t2)
        | where(!exists(select_from<Friendship>("1")
            | where(("user_id1"_t1 == "u1"_t1 && "user_id2"_t1 == "u2"_t1) ||
                    ("user_id1"_t1 == "u2"_t1 && "user_id2"_t1 == "u1"_t1)))
        | to<std::vector<Recommendation>>;

    auto same_city_recs_result = same_city_recs(conn);

    // Combine all recommendations
    std::vector<Recommendation> all_recs;
    all_recs.reserve(friend_of_friend.size() + same_city_recs_result.size());
    all_recs.insert(all_recs.end(), friend_of_friend.begin(), friend_of_friend.end());
    all_recs.insert(all_recs.end(), same_city_recs_result.begin(), same_city_recs_result.end());

    // Convert to FriendConnection format
    std::vector<FriendConnection> result;
    for (const auto& rec : all_recs) {
        result.push_back(FriendConnection{.user1_name = rec.username,
                                          .user2_name = rec.recommended_username});
    }

    return result;
}

}  // namespace analyze_social_network
