std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen::literals;

  // 1. Create an in-memory database connection
  auto conn_result = sqlgen::sqlite::connect(":memory:");
  if (!conn_result) {
    throw std::runtime_error("Failed to create database connection");
  }
  auto conn = conn_result.value();

  // 2. Create a temporary table for OrderItem data
  auto create_table_sql = R"(
    CREATE TEMPORARY TABLE OrderItem (
      item_id INTEGER PRIMARY KEY,
      order_id INTEGER NOT NULL,
      product_id INTEGER NOT NULL,
      unit_price REAL NOT NULL,
      quantity INTEGER NOT NULL,
      discount_rate REAL,
      tax_rate REAL
    )
  )";
  auto create_result = conn->execute(create_table_sql);
  if (!create_result) {
    throw std::runtime_error("Failed to create table");
  }

  // 3. Insert the input data into the table
  if (!items.empty()) {
    auto insert_sql = "INSERT INTO OrderItem VALUES ";
    for (size_t i = 0; i < items.size(); ++i) {
      if (i > 0) insert_sql += ", ";
      insert_sql += "(" + std::to_string(items[i].item_id) + ", " +
                   std::to_string(items[i].order_id) + ", " +
                   std::to_string(items[i].product_id) + ", " +
                   std::to_string(items[i].unit_price) + ", " +
                   std::to_string(items[i].quantity) + ", " +
                   (items[i].discount_rate ? std::to_string(*items[i].discount_rate) : "NULL") + ", " +
                   (items[i].tax_rate ? std::to_string(*items[i].tax_rate) : "NULL") + ")";
    }
    auto insert_result = conn->execute(insert_sql);
    if (!insert_result) {
      throw std::runtime_error("Failed to insert data");
    }
  }

  // 4. Use sqlgen's select_from with arithmetic operations to calculate all required metrics
  auto query = sqlgen::select_from<OrderItem>(
    "item_id"_c,
    "order_id"_c,
    "product_id"_c,
    "unit_price"_c,
    "quantity"_c,
    "discount_rate"_c,
    "tax_rate"_c,
    ("unit_price"_c * "quantity"_c).as<"gross_total">(),
    (("unit_price"_c * "quantity"_c) * (1 - coalesce("discount_rate"_c, 0.0)/100)).as<"discounted_total">(),
    (("unit_price"_c * "quantity"_c) * (1 - coalesce("discount_rate"_c, 0.0)/100) * (1 + coalesce("tax_rate"_c, 0.0)/100)).as<"final_total">(),
    (("unit_price"_c * "quantity"_c) / "quantity"_c).as<"unit_cost">(),
    ("quantity"_c % 10).as<"quantity_group">(),
    ("unit_price"_c * 0.3).as<"estimated_profit">()
