 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  using namespace sqlgen::literals;

  try {
    // 1. Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
      return false;
    }
    auto conn = conn_result.value();

    // 2. Create the Account table using write with empty vector
    std::vector<Account> empty_accounts;
    auto write_result = sqlgen::write(conn, empty_accounts);
    if (!write_result) {
      return false;
    }

    // 3. Update balances and statuses using set operations
    // Update account with account_id = 1
    auto update_stmt = sqlgen::update<Account>(
        "balance"_c.set(1000.0),  // Set balance to 1000.0
        "status"_c.set("ACTIVE")  // Set status to "ACTIVE"
    ) | sqlgen::where("account_id"_c == 1);  // Where condition using &&

    // 4. Execute the update using the connection
    auto update_result = update_stmt(conn);
    if (!update_result) {
      return false;
    }

    // 5. Read back data to verify changes
    std::vector<Account> updated_accounts;
    auto read_result = sqlgen::read<std::vector<Account>>(conn);
    if (!read_result) {
      return false;
    }
    updated_accounts = read_result.value();

    // Verify the update was successful
    bool success = false;
    for (const auto& account : updated_accounts) {
      if (account.account_id == 1 && 
          account.balance == 1000.0 && 
          account.status == "ACTIVE") {
        success = true;
        break;
      }
    }

    return success;

  } catch (const std::exception& e) {
    return false;
  }
}

}  // namespace update_set_operations

