  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // 1. Connect to SQLite database
  auto conn = sqlgen::sqlite::connect(":memory:");

  // 2. Create tables
  auto create_dept = sqlgen::create_table<Department>;
  auto create_emp = sqlgen::create_table<Employee>;

  create_dept(conn);
  create_emp(conn);

  // 3. Insert data
  auto insert_dept = sqlgen::insert(depts);
  auto insert_emp = sqlgen::insert(emps);

  insert_dept(conn);
  insert_emp(conn);

  // 4. Perform INNER JOIN
  auto inner_query = sqlgen::select_from<Department, "d">(
      "department_name"_t1, "first_name"_t2, "last_name"_t2, "salary"_t2
    ) | sqlgen::inner_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
      | sqlgen::to<std::vector<JoinResult>>;

  auto inner_result = inner_query(conn);

  // 5. Perform LEFT JOIN
  auto left_query = sqlgen::select_from<Employee, "e">(
      "first_name"_t2, "last_name"_t2, "salary"_t2, "department_name"_t1
    ) | sqlgen::left_join<Department, "d">("department_id"_t2 == "department_id"_t1)
      | sqlgen::to<std::vector<JoinResult>>;

  auto left_result = left_query(conn);

  // 6. Perform RIGHT JOIN
  auto right_query = sqlgen::select_from<Department, "d">(
      "department_name"_t1, "first_name"_t2, "last_name"_t2, "salary"_t2
    ) | sqlgen::right_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
      | sqlgen::to<std::vector<JoinResult>>;

  auto right_result = right_query(conn);

  // 7. Perform FULL JOIN
  auto full_query = sqlgen::select_from<Employee, "e">(
      "first_name"_t2, "last_name"_t2, "salary"_t2, "department_name"_t1
    ) | sqlgen::full_join<Department, "d">("department_id"_t2 == "department_id"_t1)
      | sqlgen::to<std::vector<JoinResult>>;

  auto full_result = full_query(conn);

  // 8. Return comprehensive analysis
  JoinAnalysis analysis;
  analysis.inner_join_results = std::move(inner_result.value());
  analysis.left_join_results = std::move(left_result.value());
  analysis.right_join_results = std::move(right_result.value());
  analysis.full_join_results = std::move(full_result.value());

  return analysis;
}

}  // namespace analyze_department_employees
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect(":memory:")` to create an in-memory SQLite database connection.

2. **Table Creation**: Uses `sqlgen::create_table<T>()` to create Department and Employee tables based on the struct definitions.

3. **Data Insertion**: Uses `sqlgen::insert()` to insert the provided department and employee data into their respective tables.

4. **Join Operations**:
   - **INNER JOIN**: Matches employees with their departments
   - **LEFT JOIN**: Includes all employees even if they don't have departments
   - **RIGHT JOIN**: Includes all departments even if they have no employees
   - **FULL JOIN**: Combines all records from both tables

5. **Query Construction**: Uses sqlgen's fluent API with `select_from`, `inner_join`, `left_join`, `right_join`, and `full_join` functions, leveraging table aliases ("d" for Department, "e" for Employee) and column literals.

6. **Result Handling**: Uses `sqlgen::to<std::vector<JoinResult>>` to map query results to the custom `JoinResult` struct, which handles optional fields for NULL values in outer joins.

7. **Comprehensive Analysis**: Returns all four join results in a structured format for further analysis.

This implementation demonstrates proper usage of sqlgen's type-safe query building, join operations, and result mapping capabilities as specified in the assessment objectives.

